class Solution:
    def circularGameLosers(self, n: int, k: int) -> List[int]:
        current = 0  # 0-based index for the first friend
        visited = set()
        visited.add(current)

        i = 1
        while True:
            current = (current + i * k) % n
            if current in visited:
                break
            visited.add(current)
            i += 1

        losers = []
        for i in range(n):
            if i not in visited:
                losers.append(i + 1)  # Convert back to 1-based indexing

        return losers
